fn insert_sorted(v: i64, arr: i64, n: i64) -> i64
    pre n >= 0
    post ret == n + 1
= {
    // Find insertion position: first index where arr[i] >= v
    let mut i = 0;
    while i < n {
        if vec_get(arr, i) >= v {
            break
        };
        i = i + 1
    };

    // Insert v at position i by shifting elements right
    // We need to make space. The array has capacity for at least n+1 elements?
    // The problem says input is sorted array of n elements. We assume we can push.
    // But to maintain sorted order efficiently, we shift from end to i.

    // Actually, simpler approach: push v to end, then bubble it to correct position?
    // Or: shift elements from i to n-1 to i+1 to n, then set arr[i] = v.
    // Since vec is dynamic, we can just push v, then move it left.

    let _p = vec_push(arr, v);
    let mut j = n; // current position of the new element (was at end)
    while j > 0 {
        let prev = vec_get(arr, j - 1);
        let curr = vec_get(arr, j);
        if prev <= curr {
            break
        };
        // Swap arr[j-1] and arr[j]
        let _s1 = vec_set(arr, j - 1, curr);
        let _s2 = vec_set(arr, j, prev);
        j = j - 1
    };

    vec_len(arr)
};

